// ---------------------------------------------------------------------------
// Parametrized Login Test
// Iterates over loginCases, sends each pair via pm.sendRequest, and asserts
// the expected outcome (success vs. failure).
// ---------------------------------------------------------------------------

const loginCases = [
  {
    scenario: "API - Login - Invalid email and invalid password",
    email: "invalidemail",
    password: "wrongpassword",
    successExpected: false,
  },
  {
    scenario: "API - Login - Correct email and incorrect password",
    email: pm.environment.get("USER_EMAIL"),
    password: pm.environment.get("USER_PASSWORD") + "123",
    successExpected: false,
  },
  {
    scenario: "API - Login - Incorrect email and correct password",
    email: pm.environment.get("USER_EMAIL") + "abc",
    password: pm.environment.get("USER_PASSWORD"),
    successExpected: false,
  },
  {
    scenario: "API - Login - Correct email and correct password",
    email: pm.environment.get("USER_EMAIL"),
    password: pm.environment.get("USER_PASSWORD"),
    successExpected: true,
  },
];

const baseUrl = pm.environment.get("API_BASE_URL");

// Run all cases sequentially via a recursive helper
function runCase(index) {
  if (index >= loginCases.length) return;

  const tc = loginCases[index];

  pm.sendRequest(
    {
      url: baseUrl + "/api/users/login",
      method: "POST",
      header: { "Content-Type": "application/json" },
      body: {
        mode: "raw",
        raw: JSON.stringify({ user: { email: tc.email, password: tc.password } }),
      },
    },
    function (err, res) {
      const status = res ? res.code : null;
      const body   = res ? res.json() : null;

      if (tc.successExpected) {
        pm.test(tc.scenario + " — status is 200", function () {
          pm.expect(err).to.be.null;
          pm.expect(status).to.equal(200);
        });

        pm.test(tc.scenario + " — response has user object", function () {
          pm.expect(body).to.have.property("user");
        });

        pm.test(tc.scenario + " — user has email, username, token", function () {
          pm.expect(body.user).to.have.property("email");
          pm.expect(body.user).to.have.property("username");
          pm.expect(body.user).to.have.property("token");
        });

        pm.test(tc.scenario + " — token is a non-empty string", function () {
          pm.expect(body.user.token).to.be.a("string").and.to.have.length.above(0);
        });

        // Persist token for subsequent requests only on the success case
        if (body && body.user && body.user.token) {
          pm.environment.set("AUTH_TOKEN", body.user.token);
        }
      } else {
        pm.test(tc.scenario + " — status is 4xx (not 200)", function () {
          pm.expect(err).to.be.null;
          pm.expect(status).to.be.within(400, 499);
        });

        pm.test(tc.scenario + " — response does NOT contain a token", function () {
          const hasToken = body && body.user && body.user.token;
          pm.expect(hasToken).to.be.falsy;
        });
      }

      runCase(index + 1);
    }
  );
}

