pm.test("Read Article - Status 200", function () {
    try {
        pm.response.to.have.status(200);
        const response = pm.response.json();
        pm.expect(response.article.slug).to.eql(pm.environment.get("ARTICLE_SLUG"));
    } catch (err) {
        console.log("[Error] Read failed. Routing to cleanup.");
        pm.execution.setNextRequest("05_Delete_Article");
        throw err;
    }
});

pm.test("Update Article - Status 200", function () {
    try {
        pm.response.to.have.status(200);
        const response = pm.response.json();
        pm.expect(response.article.title).to.eql("Updated Postman Test Article");

        // Update slug in case the title change modified it
        pm.environment.set("ARTICLE_SLUG", response.article.slug); 
    } catch (err) {
        console.log("[Error] Update failed. Routing to cleanup.");
        pm.execution.setNextRequest("05_Delete_Article");
        throw err;
    }
});

pm.test("Delete Article - Status 200 or 204", function () {
    // Conduit typically responds with 200 or 204 on deletion
    pm.expect(pm.response.code).to.be.oneOf([200, 204]);
    console.log(`[Cleanup] Successfully deleted article: ${pm.environment.get("ARTICLE_SLUG")}`);
});

pm.test("Verify Article Absent - Status 404", function () {
    pm.response.to.have.status(404);

    // Clean up environment variables so they don't linger for the next run
    pm.environment.unset("ARTICLE_SLUG");
    console.log("[CRUD] Verification complete. Environment wiped clean.");
});
